type Logo = {
  name: string;
  brandLight: string;
  brandDark?: string;
  height: number;
  multicolor: boolean;
  pixelColors: string[];
  row: number;
  col: number;
  Svg: React.ComponentType<LogoSvgProps>;
};

const LOGOS: Logo[] = [
  { name: "Slack", brandLight: "#611F69", brandDark: "#A28BB8", height: 22, multicolor: true, pixelColors: ["#2FBDEE", "#29AD72", "#E9A929", "#DC1C50"], row: 1, col: 1, Svg: SlackLogo },
  { name: "Stripe", brandLight: "#635BFF", height: 20, multicolor: false, pixelColors: ["#635BFF", "#7B75FF", "#A39FFF"], row: 1, col: 2, Svg: StripeLogo },
  { name: "Medium", brandLight: "#1A1A1A", brandDark: "#FAFAFA", height: 22, multicolor: false, pixelColors: ["#1A1A1A", "#FAFAFA", "#A0A0A0"], row: 1, col: 3, Svg: MediumLogo },
  { name: "Netflix", brandLight: "#D81F26", brandDark: "#E50914", height: 16, multicolor: false, pixelColors: ["#D81F26", "#E50914", "#FF3A3A"], row: 1, col: 4, Svg: NetflixLogo },
  { name: "Google", brandLight: "#4285F4", height: 20, multicolor: true, pixelColors: ["#4285F4", "#EA4335", "#FBBC05", "#34A853"], row: 1, col: 5, Svg: GoogleLogo },

  { name: "LinkedIn", brandLight: "#0A66C2", brandDark: "#3D8DDE", height: 20, multicolor: false, pixelColors: ["#0A66C2", "#2D8CDB", "#5BA8E6"], row: 2, col: 1, Svg: LinkedInLogo },
  { name: "Microsoft", brandLight: "#F25022", height: 20, multicolor: true, pixelColors: ["#F25022", "#7FBA00", "#00A4EF", "#FFB900"], row: 2, col: 5, Svg: MicrosoftLogo },

  { name: "Airbnb", brandLight: "#FF5A5F", height: 24, multicolor: false, pixelColors: ["#FF5A5F", "#FF787C", "#FF9A9D"], row: 3, col: 1, Svg: AirbnbLogo },
  { name: "Facebook", brandLight: "#1877F2", height: 20, multicolor: false, pixelColors: ["#1877F2", "#4293F5", "#78B3FA"], row: 3, col: 5, Svg: FacebookLogo },

  { name: "Spotify", brandLight: "#1DB954", height: 22, multicolor: false, pixelColors: ["#1DB954", "#1ED760", "#56E889"], row: 4, col: 1, Svg: SpotifyLogo },
  { name: "Slack2", brandLight: "#611F69", brandDark: "#A28BB8", height: 22, multicolor: true, pixelColors: ["#2FBDEE", "#29AD72", "#E9A929", "#DC1C50"], row: 4, col: 2, Svg: SlackLogo },
  { name: "Stripe2", brandLight: "#635BFF", height: 20, multicolor: false, pixelColors: ["#635BFF", "#7B75FF", "#A39FFF"], row: 4, col: 3, Svg: StripeLogo },
  { name: "Google2", brandLight: "#4285F4", height: 20, multicolor: true, pixelColors: ["#4285F4", "#EA4335", "#FBBC05", "#34A853"], row: 4, col: 4, Svg: GoogleLogo },
  { name: "Netflix2", brandLight: "#D81F26", brandDark: "#E50914", height: 16, multicolor: false, pixelColors: ["#D81F26", "#E50914", "#FF3A3A"], row: 4, col: 5, Svg: NetflixLogo },
];

function LogoCard({ logo }: { logo: Logo }) {
  const { Svg, multicolor, brandLight, brandDark, height, pixelColors, row, col } = logo;

  return (
    <div
      className={cn(
        "group relative grid place-items-center overflow-hidden bg-card cursor-pointer select-none isolate",
        "transition-shadow duration-300 hover:z-[2]",
        "[--brand:var(--brand-light)] dark:[--brand:var(--brand-dark)]",
        "hover:shadow-[0_8px_24px_-8px_color-mix(in_srgb,var(--brand)_25%,transparent),0_0_0_1px_color-mix(in_srgb,var(--brand)_40%,transparent)]",
      )}
      style={
        {
          "--brand-light": brandLight,
          "--brand-dark": brandDark ?? brandLight,
          gridRow: row,
          gridColumn: col,
        } as React.CSSProperties
      }
    >
      <PixelCanvas colors={pixelColors} gap={5} speed={30} />
      <Svg
        className={cn(
          "relative z-[1] w-auto max-w-[65%] transition-all duration-300 group-hover:scale-[1.06]",
          multicolor
            ? cn(
                "grayscale opacity-50 dark:brightness-0 dark:invert",
                "group-hover:grayscale-0 group-hover:opacity-100",
                "dark:group-hover:brightness-100 dark:group-hover:invert-0",
              )
            : "text-muted-foreground/60 group-hover:text-[var(--brand)]",
        )}
        style={{ height: `${height}px`, maxHeight: `${height}px` }}
      />
    </div>
  );
}

